"use client"

import React, { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  FileCode, Plus, Trash2, Edit3, CheckCircle, AlertTriangle,
  X, RefreshCw, ShieldCheck, Cpu, KeyRound, Activity, Copy,
  Sparkles, ShieldAlert, EyeOff, Fingerprint, Timer, Loader2,
} from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";

interface Script {
  id: string;
  name: string;
  description: string | null;
  version: string;
  content: string;
  visibility: "PUBLIC" | "PRIVATE" | "OBFUSCATED";
  channel: "STABLE" | "BETA";
  status: "ACTIVE" | "MAINTENANCE" | "DISABLED";
  category: string | null;
  createdAt: string;
}

export default function ScriptManager() {
  const { toast } = useToast();
  const [scripts, setScripts] = useState<Script[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [resultModalOpen, setResultModalOpen] = useState(false);
  const [resultLoadstring, setResultLoadstring] = useState("");
  const [resultScriptName, setResultScriptName] = useState("");
  const [saving, setSaving] = useState(false);
  const [editingScript, setEditingScript] = useState<Script | null>(null);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [version, setVersion] = useState("1.0.0");
  const [content, setContent] = useState("");
  const [category, setCategory] = useState("General");
  const [obfuscate, setObfuscate] = useState(false);
  const [keyMode, setKeyMode] = useState<"key" | "keyless">("key");
  const [uiLibrary, setUiLibrary] = useState<"firelab" | "custom">("firelab");

  async function fetchScripts() {
    try {
      setLoading(true);
      const res = await fetch("/api/scripts");
      const data = await res.json();
      if (data.scripts) setScripts(data.scripts);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => { fetchScripts(); }, []);

  const resetForm = () => {
    setName(""); setDescription(""); setVersion("1.0.0"); setContent("");
    setCategory("General"); setObfuscate(false); setKeyMode("key");
    setEditingScript(null);
  };

  const buildLoadstring = (scriptId: string, keyless: boolean, useCustomUi: boolean) => {
    const origin = typeof window !== "undefined" ? window.location.origin : "";
    const loaderUrl = `${origin}/api/v1/loader/${scriptId}`;
    const params = useCustomUi ? "?ui=custom" : "";
    if (keyless) {
      return `loadstring(game:HttpGet("${loaderUrl}${params}"))()`;
    }
    return `script_key = script_key or "" -- Set your key here or leave empty for prompt
loadstring(game:HttpGet("${loaderUrl}${params}"))()`;
  };

  const handleCreateOrUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!content.trim()) return;
    setSaving(true);

    const payload = {
      name, description, version, content,
      obfuscate,
      visibility: (keyMode === "keyless" ? "PUBLIC" : obfuscate ? "OBFUSCATED" : "PRIVATE") as "PUBLIC" | "OBFUSCATED" | "PRIVATE",
      channel: "STABLE" as const,
      status: "ACTIVE" as const,
      category,
    };

    try {
      const url = editingScript ? `/api/scripts/${editingScript.id}` : "/api/scripts";
      const method = editingScript ? "PUT" : "POST";
      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const data = await res.json();
      if (res.ok && data.script) {
        const scriptId = data.script.id;
        const ls = buildLoadstring(scriptId, keyMode === "keyless", uiLibrary === "custom");
        setResultLoadstring(ls);
        setResultScriptName(data.script.name);
        setModalOpen(false);
        setResultModalOpen(true);
        resetForm();
        fetchScripts();
      } else {
        toast({ variant: "destructive", title: "Error", description: data.error || "Failed to protect script" });
      }
    } catch (err) {
      toast({ variant: "destructive", title: "Error", description: "Failed to connect to server" });
      console.error(err);
    } finally {
      setSaving(false);
    }
  };

  const handleEditClick = (script: Script) => {
    setEditingScript(script);
    setName(script.name);
    setDescription(script.description || "");
    setVersion(script.version);
    setContent(script.content);
    setCategory(script.category || "General");
    setObfuscate(script.visibility === "OBFUSCATED");
    setModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Delete this protected script?")) return;
    try {
      const res = await fetch(`/api/scripts/${id}`, { method: "DELETE" });
      if (res.ok) fetchScripts();
      else toast({ variant: "destructive", title: "Error", description: "Failed to delete script" });
    } catch (err) { console.error(err); }
  };

  const copyToClipboard = async (text: string) => {
    await navigator.clipboard.writeText(text);
  };

  const copyLoadstring = (script: Script) => {
    const keyless = script.visibility === "PUBLIC";
    const ls = buildLoadstring(script.id, keyless, false);
    copyToClipboard(ls);
    toast({ variant: "success", title: "Copied!", description: "Loadstring copied to clipboard" });
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-white tracking-tight glow-red">FireLab Script Protector</h1>
          <p className="text-gray-400 text-sm mt-1">Upload source, get a loadstring, and control access from one place.</p>
        </div>
        <Button onClick={() => { resetForm(); setModalOpen(true); }} className="gap-2" variant="glow">
          <Plus className="h-4 w-4" /> Protect Script
        </Button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
        {[
          { title: "Loadstring", desc: "Turns source into a protected payload", icon: FileCode },
          { title: "HWID Lock", desc: "Bind access to customer devices", icon: KeyRound },
          { title: "License Gate", desc: "Only active keys can request access", icon: ShieldCheck },
          { title: "Anti-Replay", desc: "Reject stale or reused auth responses", icon: Timer },
          { title: "Anti-Tamper", desc: "Verify payload, loader, and patch anchors", icon: ShieldAlert },
          { title: "Anti-Debug", desc: "Detect hooks, inspection, and debug traces", icon: EyeOff },
          { title: "Anti-Env", desc: "Flag spoofed, virtualized, or sandboxed executors", icon: Fingerprint },
          { title: "Runtime Checks", desc: "Keep validating while the payload is alive", icon: Cpu },
        ].map((item) => (
          <motion.div whileHover={{ y: -4 }} key={item.title} className="glass-panel rounded-xl p-4 border-red-500/10">
            <div className="flex items-center justify-between">
              <item.icon className="h-5 w-5 text-red-400" />
              <Activity className="h-4 w-4 text-gray-500" />
            </div>
            <div className="text-sm font-black text-white mt-4">{item.title}</div>
            <div className="text-xs text-gray-400 mt-1 leading-5">{item.desc}</div>
          </motion.div>
        ))}
      </div>

      {loading ? (
        <div className="flex justify-center py-20">
          <RefreshCw className="h-10 w-10 text-red-500 animate-spin" />
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {scripts.length === 0 ? (
            <div className="col-span-full py-20 text-center text-gray-400 border border-red-500/10 bg-black/20 rounded-xl">
              <FileCode className="h-12 w-12 text-red-500 mx-auto mb-4" />
              <p className="font-semibold text-lg text-white">No protected scripts yet</p>
              <p className="text-sm text-gray-500 mt-1">Protect your first script to get a loadstring.</p>
            </div>
          ) : (
            scripts.map((script) => (
              <Card key={script.id} className="glass-panel-hover relative overflow-hidden flex flex-col justify-between">
                <CardHeader>
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] uppercase font-mono tracking-widest bg-red-500/10 border border-red-500/25 px-2 py-0.5 rounded text-red-300">
                      {script.category || "General"}
                    </span>
                    <div className="flex items-center gap-1.5">
                      {script.status === "ACTIVE" && <span className="flex items-center gap-1 text-[10px] text-emerald-400 font-semibold uppercase bg-emerald-500/10 px-2 py-0.5 rounded border border-emerald-500/20"><CheckCircle className="h-3 w-3" /> Active</span>}
                    </div>
                  </div>
                  <CardTitle className="mt-4 flex items-center gap-2">
                    <FileCode className="h-5 w-5 text-red-400" />
                    <span>{script.name}</span>
                  </CardTitle>
                  <CardDescription className="line-clamp-2 mt-1">{script.description || "Protected script payload."}</CardDescription>
                </CardHeader>
                <CardContent className="space-y-3 pt-2">
                  <div className="flex items-center justify-between text-xs">
                    <span className="text-gray-400">Version</span>
                    <span className="font-semibold text-white bg-white/5 px-2 py-0.5 rounded font-mono">{script.version}</span>
                  </div>
                  <div className="flex items-center justify-between text-xs">
                    <span className="text-gray-400">Protection</span>
                    <span className="font-semibold text-white flex items-center gap-1"><Cpu className="h-3 w-3 text-red-400" /> {script.visibility}</span>
                  </div>
                </CardContent>
                <CardFooter className="flex items-center justify-between gap-2 border-t border-red-500/10 pt-4">
                  <Button size="sm" variant="outline" onClick={() => copyLoadstring(script)} className="h-8 border-red-500/20 hover:bg-red-950/20 text-red-300">
                    <Copy className="h-3.5 w-3.5 mr-1" /> Loadstring
                  </Button>
                  <div className="flex gap-2">
                    <Button size="sm" variant="outline" onClick={() => handleEditClick(script)} className="h-8 border-red-500/20 hover:bg-red-950/20"><Edit3 className="h-3.5 w-3.5" /></Button>
                    <Button size="sm" variant="destructive" onClick={() => handleDelete(script.id)} className="h-8 bg-red-950/40 text-red-400 border border-red-500/20 hover:bg-red-500 hover:text-white"><Trash2 className="h-3.5 w-3.5" /></Button>
                  </div>
                </CardFooter>
              </Card>
            ))
          )}
        </div>
      )}

      {/* Create/Edit Modal */}
      <AnimatePresence>
        {modalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
            <motion.div initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }} className="bg-[#0b0f19] border border-red-500/15 rounded-2xl p-6 max-w-2xl w-full space-y-4 max-h-[90vh] overflow-y-auto shadow-[0_0_80px_rgba(239,68,68,0.18)]">
              <div className="flex items-center justify-between pb-2 border-b border-red-500/10">
                <h2 className="text-xl font-black text-white">{editingScript ? "Edit Script" : "Protect New Script"}</h2>
                <button onClick={() => setModalOpen(false)} className="text-gray-400 hover:text-white"><X className="h-5 w-5" /></button>
              </div>

              <form onSubmit={handleCreateOrUpdate} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs text-gray-400 font-semibold uppercase">Script Name</label>
                    <Input value={name} onChange={(e) => setName(e.target.value)} placeholder="e.g. Premium Hub" required />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs text-gray-400 font-semibold uppercase">Category</label>
                    <Input value={category} onChange={(e) => setCategory(e.target.value)} placeholder="e.g. Roblox" />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs text-gray-400 font-semibold uppercase">Version</label>
                    <Input value={version} onChange={(e) => setVersion(e.target.value)} required />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs text-gray-400 font-semibold uppercase">Description</label>
                    <Input value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Brief notes..." />
                  </div>
                </div>

                {/* Key mode selector */}
                <div className="space-y-2">
                  <label className="text-xs text-gray-400 font-semibold uppercase">Access Mode</label>
                  <div className="grid grid-cols-2 gap-3">
                    <button
                      type="button"
                      onClick={() => setKeyMode("key")}
                      className={`flex flex-col items-center gap-2 p-4 rounded-xl border transition-all ${keyMode === "key" ? "border-red-500/40 bg-red-500/10" : "border-white/10 bg-black/40 hover:border-white/20"}`}
                    >
                      <KeyRound className={`h-6 w-6 ${keyMode === "key" ? "text-red-400" : "text-gray-500"}`} />
                      <span className={`text-sm font-bold ${keyMode === "key" ? "text-white" : "text-gray-500"}`}>Key Required</span>
                      <span className="text-[10px] text-gray-500 text-center">Users need a license key to run the script</span>
                    </button>
                    <button
                      type="button"
                      onClick={() => setKeyMode("keyless")}
                      className={`flex flex-col items-center gap-2 p-4 rounded-xl border transition-all ${keyMode === "keyless" ? "border-red-500/40 bg-red-500/10" : "border-white/10 bg-black/40 hover:border-white/20"}`}
                    >
                      <EyeOff className={`h-6 w-6 ${keyMode === "keyless" ? "text-red-400" : "text-gray-500"}`} />
                      <span className={`text-sm font-bold ${keyMode === "keyless" ? "text-white" : "text-gray-500"}`}>Keyless</span>
                      <span className="text-[10px] text-gray-500 text-center">Anyone can run the script without a key</span>
                    </button>
                  </div>
                </div>

                {/* UI Library selector */}
                <div className="space-y-2">
                  <label className="text-xs text-gray-400 font-semibold uppercase">UI Library</label>
                  <div className="grid grid-cols-2 gap-3">
                    <button
                      type="button"
                      onClick={() => setUiLibrary("firelab")}
                      className={`flex items-center gap-3 p-3 rounded-xl border transition-all ${uiLibrary === "firelab" ? "border-red-500/40 bg-red-500/10" : "border-white/10 bg-black/40 hover:border-white/20"}`}
                    >
                      <ShieldCheck className={`h-5 w-5 ${uiLibrary === "firelab" ? "text-red-400" : "text-gray-500"}`} />
                      <div className="text-left">
                        <span className={`text-sm font-bold block ${uiLibrary === "firelab" ? "text-white" : "text-gray-500"}`}>FireLab UI</span>
                        <span className="text-[10px] text-gray-500">Use our built-in key prompt UI</span>
                      </div>
                    </button>
                    <button
                      type="button"
                      onClick={() => setUiLibrary("custom")}
                      className={`flex items-center gap-3 p-3 rounded-xl border transition-all ${uiLibrary === "custom" ? "border-red-500/40 bg-red-500/10" : "border-white/10 bg-black/40 hover:border-white/20"}`}
                    >
                      <FileCode className={`h-5 w-5 ${uiLibrary === "custom" ? "text-red-400" : "text-gray-500"}`} />
                      <div className="text-left">
                        <span className={`text-sm font-bold block ${uiLibrary === "custom" ? "text-white" : "text-gray-500"}`}>Custom UI</span>
                        <span className="text-[10px] text-gray-500">Use your own UI library (Rayfield, etc.)</span>
                      </div>
                    </button>
                  </div>
                </div>

                {/* Obfuscation toggle */}
                <label className="flex items-center gap-3 rounded-xl border border-red-500/15 bg-red-500/10 p-4 cursor-pointer">
                  <input type="checkbox" checked={obfuscate} onChange={(e) => setObfuscate(e.target.checked)} className="h-4 w-4 accent-red-500" />
                  <div>
                    <div className="text-sm font-black text-white flex items-center gap-2"><Sparkles className="h-4 w-4 text-red-400" /> Obfuscate Source</div>
                    <div className="text-xs text-gray-400 mt-1">Encrypts your Luau source. Recommended.</div>
                  </div>
                </label>

                <div className="space-y-1">
                  <label className="text-xs text-gray-400 font-semibold uppercase">Source / Luau Payload</label>
                  <textarea value={content} onChange={(e) => setContent(e.target.value)} required rows={9} className="flex w-full rounded-lg border border-white/10 bg-white/[0.04] px-4 py-3 text-sm text-white font-mono focus:outline-none focus:ring-2 focus:ring-red-500/50" placeholder="print('Hello from FireLab!')" />
                </div>

                <div className="flex justify-end gap-2 border-t border-red-500/10 pt-4">
                  <Button type="button" variant="outline" onClick={() => setModalOpen(false)}>Cancel</Button>
                  <Button type="submit" variant="glow" disabled={saving}>
                    {saving ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
                    {editingScript ? "Save Changes" : "Protect Script"}
                  </Button>
                </div>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* Result Modal — shows loadstring after saving */}
      <AnimatePresence>
        {resultModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
            <motion.div initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }} className="bg-[#0b0f19] border border-red-500/15 rounded-2xl p-6 max-w-lg w-full space-y-4 shadow-[0_0_80px_rgba(239,68,68,0.18)]">
              <div className="flex items-center gap-3 pb-2 border-b border-red-500/10">
                <CheckCircle className="h-8 w-8 text-emerald-400" />
                <div>
                  <h2 className="text-xl font-black text-white">Script Protected!</h2>
                  <p className="text-xs text-gray-400 mt-1">{resultScriptName} is now live and ready to use.</p>
                </div>
              </div>

              <div>
                <div className="flex items-center justify-between mb-2">
                  <span className="text-xs uppercase tracking-widest text-red-300 font-black">Your Loadstring</span>
                  <button onClick={() => copyToClipboard(resultLoadstring)} className="flex items-center gap-1 text-xs text-red-300 hover:text-white transition-colors">
                    <Copy className="h-3.5 w-3.5" /> Copy
                  </button>
                </div>
                <div className="bg-black/60 border border-red-500/10 rounded-xl p-4 font-mono text-xs text-gray-300 whitespace-pre-wrap break-all">
                  {resultLoadstring}
                </div>
              </div>

              <div className="bg-red-500/5 border border-red-500/10 rounded-xl p-3">
                <p className="text-xs text-gray-400">
                  {keyMode === "key" ? (
                    <>Users need a valid license key. Generate keys in the <strong className="text-red-300">Keys</strong> tab, then users set <code className="text-red-300">script_key = "LUA-XXXXX-XXXXX-XXXXX"</code> before running.</>
                  ) : (
                    <>This script is <strong className="text-red-300">keyless</strong> — anyone can run it without a key.</>
                  )}
                </p>
              </div>

              <div className="flex justify-end gap-2 pt-2">
                <Button onClick={() => setResultModalOpen(false)} variant="glow">Done</Button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { rateLimit } from "@/lib/rate-limit";
import { getRateLimitHeaders } from "@/lib/rate-limit";
import { decryptObject, hashString, hashToken } from "@/lib/crypto";
import { getClientIp, hashIdentifier } from "@/lib/http";
import { recordSecurityFailure } from "@/lib/ip-reputation";
import { sendDiscordLog } from "@/lib/discord-logger";

function parseQuery(url: URL) {
  return {
    key: url.searchParams.get("key") || "",
    hwid: url.searchParams.get("hwid") || "",
    scriptId: url.searchParams.get("scriptId") || "",
    nonce: url.searchParams.get("nonce") || "",
    timestamp: url.searchParams.get("ts") ? Number(url.searchParams.get("ts")) : undefined,
    executor: url.searchParams.get("executor") || "Unknown",
    check: url.searchParams.get("check") === "1",
  };
}

function errorResponse(message: string, status = 401) {
  return new NextResponse(`ERROR: ${message}`, {
    status,
    headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" },
  });
}

export async function GET(req: Request) {
  return handleAuth(req);
}

export async function POST(req: Request) {
  return handleAuth(req);
}

async function handleAuth(req: Request) {
  const startTime = Date.now();
  const ip = getClientIp(req);
  const url = new URL(req.url);

  const limited = await rateLimit(`script-auth:${ip}`, 30, 60 * 1000);
  if (!limited.success) {
    return errorResponse("Too many requests", 429);
  }

  try {
    let parsed: ReturnType<typeof parseQuery>;

    if (req.method === "GET") {
      parsed = parseQuery(url);
    } else {
      // POST: parse JSON body
      try {
        const rawBody = await req.text();
        const body = JSON.parse(rawBody);
        parsed = {
          key: body.key || "",
          hwid: body.hwid || "",
          scriptId: body.scriptId || "",
          nonce: body.nonce || "",
          timestamp: body.timestamp,
          executor: body.executor || "Unknown",
          check: false,
        };
      } catch {
        // Fallback: try query params
        parsed = parseQuery(url);
      }
    }

    if (!parsed.key || !parsed.hwid || !parsed.scriptId) {
      return errorResponse("Missing required fields", 400);
    }

    const { key, hwid, scriptId, executor } = parsed;
    const fingerprintHash = hashIdentifier(hwid);
    const userAgent = req.headers.get("user-agent") || "LuauEngine";
    const country = req.headers.get("cf-ipcountry") || req.headers.get("x-country") || null;

    async function logAccess(success: boolean, reason: string, licenseId?: string) {
      try {
        await db.scriptAccessLog.create({
          data: { scriptId, licenseId: licenseId || null, userId: null, ip, country, success, reason, createdAt: new Date() },
        });
      } catch {}
      if (!success) {
        try { await recordSecurityFailure(ip, reason); } catch {}
      }
    }

    // Find the script
    const scriptRecord = await db.script.findUnique({
      where: { id: scriptId },
      select: { id: true, name: true, status: true, visibility: true, contentEncrypted: true, version: true, ownerId: true },
    }).catch(() => null);

    if (!scriptRecord) return errorResponse("Script not found", 404);

    if (scriptRecord.status === "DISABLED") {
      await logAccess(false, "SCRIPT_DISABLED");
      return errorResponse("Script is disabled", 403);
    }

    // Keyless mode — PUBLIC scripts don't require a license key
    if (scriptRecord.visibility === "PUBLIC" || key.startsWith("KEYLESS")) {
      await logAccess(true, "KEYLESS_ACCESS");

      void sendDiscordLog({
        event: "Script Auth — Keyless", key: "KEYLESS", scriptName: scriptRecord.name,
        ip, country, device: userAgent, hwid, success: true, timestamp: new Date().toISOString(),
      });

      const scriptPayload = decryptObject<{ key: string }>(scriptRecord.contentEncrypted).key;
      return new NextResponse(scriptPayload, {
        headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "private, no-store" },
      });
    }

    // Key-based auth
    const keyHash = hashToken(key);
    const license = await db.license.findUnique({
      where: { keyHash },
      include: { script: { include: { protectionProfile: true } }, hwids: { orderBy: { createdAt: "desc" } } },
    });

    if (!license || license.scriptId !== scriptId) {
      await logAccess(false, "INVALID_LICENSE_OR_SCRIPT_BINDING");
      return errorResponse("Invalid license key or script binding");
    }

    if (license.script.status === "DISABLED") {
      await logAccess(false, "SCRIPT_DISABLED", license.id);
      return errorResponse("Script is disabled", 403);
    }

    // Auto-redeem UNREDEEMED keys on first use
    if (license.status === "UNREDEEMED") {
      let expiresAt: Date | null = null;
      if (license.type === "SUBSCRIPTION" && license.durationDays) {
        expiresAt = new Date(Date.now() + license.durationDays * 24 * 60 * 60 * 1000);
      }
      await db.license.update({
        where: { id: license.id },
        data: { status: "ACTIVE", redeemedAt: new Date(), redeemedBy: hwid, expiresAt },
      }).catch(() => {});
    }

    if (license.status === "SUSPENDED") {
      await logAccess(false, "LICENSE_SUSPENDED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Suspended", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License suspended", timestamp: new Date().toISOString() });
      return errorResponse("License has been suspended", 403);
    }
    if (license.status === "BLACKLISTED") {
      await logAccess(false, "LICENSE_BLACKLISTED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Blacklisted", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License blacklisted", timestamp: new Date().toISOString() });
      return errorResponse("License is blacklisted", 403);
    }
    if (license.status === "EXPIRED" || (license.expiresAt && new Date() > license.expiresAt)) {
      if (license.status !== "EXPIRED") {
        await db.license.update({ where: { id: license.id }, data: { status: "EXPIRED" } });
      }
      await logAccess(false, "LICENSE_EXPIRED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Expired", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License expired", timestamp: new Date().toISOString() });
      return errorResponse("License has expired", 403);
    }

    // HWID lock — auto-bind on first use
    let hwidRecord = await db.hwid.findFirst({ where: { licenseId: license.id, fingerprintHash } });
    if (license.hwidLock) {
      if (!hwidRecord && license.hwids.length > 0) {
        await logAccess(false, "HWID_MISMATCH", license.id);
        void sendDiscordLog({ event: "Script Auth — HWID Mismatch", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "HWID mismatch", timestamp: new Date().toISOString() });
        return errorResponse("HWID mismatch — reset HWID from dashboard");
      }
      if (!hwidRecord) {
        hwidRecord = await db.hwid.create({
          data: { licenseId: license.id, fingerprintHash, source: "auth", lastIp: ip, lastDeviceInfo: userAgent },
        });
      } else {
        await db.hwid.update({ where: { id: hwidRecord.id }, data: { lastIp: ip, lastDeviceInfo: userAgent } });
      }
    }

    // Log the activation
    await db.activation.create({
      data: { licenseId: license.id, hwidId: hwidRecord?.id || null, fingerprintHash, ip, country, deviceInfo: userAgent, userAgent, success: true },
    }).catch(() => {});

    await logAccess(true, "AUTH_SUCCESS", license.id);

    void sendDiscordLog({
      event: "Script Authentication", key, scriptName: license.script.name,
      ip, country, device: userAgent, hwid, success: true, timestamp: new Date().toISOString(),
    });

    const scriptPayload = decryptObject<{ key: string }>(license.script.contentEncrypted).key;

    return new NextResponse(scriptPayload, {
      headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "private, no-store" },
    });
  } catch (error) {
    console.error("Auth script endpoint error:", error);
    return errorResponse("Internal server error", 500);
  }
}

import { randomBytes, createHash } from "crypto";

type Strength = "standard" | "strong" | "maximum";

type ObfuscateOptions = {
  strength?: Strength;
  profileId?: string;
  scriptId?: string;
  antiTamper?: boolean;
  antiDebug?: boolean;
  antiHook?: boolean;
  antiDump?: boolean;
  antiDecompile?: boolean;
  antiEnv?: boolean;
  antiEmulation?: boolean;
  antiPatch?: boolean;
  antiVm?: boolean;
  antiSpoof?: boolean;
  antiReplay?: boolean;
  antiKeySharing?: boolean;
  antiHwidSpoof?: boolean;
  antiBypass?: boolean;
  integrity?: boolean;
  obfuscation?: boolean;
  controlFlow?: boolean;
  stringEncryption?: boolean;
  runtimeChecks?: boolean;
  expectedExecutors?: string[];
  expectedPlaceIds?: number[];
  expectedUniverseIds?: number[];
};

const BASE64_ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

export function isLoadStringPayload(source: string) {
  // Detect already-obfuscated code by looking for the characteristic variable patterns
  return source.includes("FireLabPayload") || source.includes("_r=") && source.includes("loadstring or load");
}

function shuffleAlphabet(): string {
  const chars = BASE64_ALPHABET.split("");
  for (let i = chars.length - 1; i > 0; i--) {
    const j = randomBytes(1)[0] % (i + 1);
    [chars[i], chars[j]] = [chars[j], chars[i]];
  }
  return chars.join("");
}

function encodeCustomBase64(bytes: number[], alphabet: string): string {
  let output = "";
  for (let i = 0; i < bytes.length; i += 3) {
    const first = bytes[i];
    const second = bytes[i + 1] ?? 0;
    const third = bytes[i + 2] ?? 0;
    output += alphabet[(first >> 2) & 0x3f];
    output += alphabet[((first & 0x03) << 4) | ((second >> 4) & 0x0f)];
    output += i + 1 < bytes.length ? alphabet[((second & 0x0f) << 2) | ((third >> 6) & 0x03)] : "=";
    output += i + 2 < bytes.length ? alphabet[third & 0x3f] : "=";
  }
  return output;
}

function chunkString(value: string, size: number): string[] {
  const chunks: string[] = [];
  for (let i = 0; i < value.length; i += size) {
    chunks.push(value.slice(i, i + size));
  }
  return chunks;
}

function randomVar(prefix: string): string {
  return `_${prefix}_${randomBytes(3).toString("hex")}`;
}

// Strong obfuscation: multi-layer XOR + byte rotation + custom base64 + variable randomization
export function obfuscateLua(source: string, options: ObfuscateOptions = {}): string {
  if (!source.trim()) return source;
  if (isLoadStringPayload(source)) return source;

  const strength = options.strength ?? "strong";
  const keyLength = strength === "maximum" ? 32 : strength === "strong" ? 24 : 16;
  const rawKey = randomBytes(keyLength);
  const alphabet = shuffleAlphabet();
  const rotation = randomBytes(1)[0] % 255 || 1;

  // Layer 1: XOR with key
  const sourceBytes = Array.from(Buffer.from(source, "utf8"));
  const xoredBytes = sourceBytes.map((byte, i) => (byte ^ rawKey[i % rawKey.length]) & 0xff);

  // Layer 2: Byte rotation (add rotation value)
  const rotatedBytes = xoredBytes.map(byte => (byte + rotation) & 0xff);

  // Layer 3: Custom base64 encode
  const encoded = encodeCustomBase64(rotatedBytes, alphabet);
  const keyHex = rawKey.toString("hex");
  const checksum = createHash("sha256").update(encoded + keyHex + rotation).digest("hex").slice(0, 16);
  const chunks = chunkString(encoded, 80);

  // Randomized variable names
  const v = {
    chunks: randomVar("c"),
    key: randomVar("k"),
    alphabet: randomVar("a"),
    expected: randomVar("e"),
    idx: randomVar("i"),
    decode: randomVar("d"),
    unkey: randomVar("u"),
    hex: randomVar("h"),
    encoded: randomVar("en"),
    decoded: randomVar("de"),
    fn: randomVar("f"),
    execute: randomVar("x"),
    chunks2: randomVar("c2"),
    srcLen: randomVar("sl"),
  };

  return `local ${v.chunks}={${chunks.map(c => `[==[${c}]==]`).join(",")}}
local ${v.key}="${keyHex}"
local ${v.alphabet}="${alphabet}"
local ${v.expected}="${checksum}"
local _r=${rotation}
local ${v.srcLen}=${sourceBytes.length}
local ${v.idx}={}
for _i=1,#${v.alphabet} do ${v.idx}[${v.alphabet}:sub(_i,_i)]=_i-1 end
local function ${v.decode}(_chunk)
  local _cl=_chunk:gsub("[^"..${v.alphabet}.."=]","")
  local _o={}
  for _i=1,#_cl,4 do
    local _q=_cl:sub(_i,_i+3)
    local _a=${v.idx}[_q:sub(1,1)]
    local _b=${v.idx}[_q:sub(2,2)]
    if not _a or not _b then error("E1") end
    local _c=${v.idx}[_q:sub(3,3)]
    local _d=${v.idx}[_q:sub(4,4)]
    if _q:sub(4,4)=="=" then
      if _q:sub(3,3)=="=" then
        _o[#_o+1]=(_a*4+math.floor(_b/16))%256
      else
        if not _c then error("E2") end
        _o[#_o+1]=(_a*4+math.floor(_b/16))%256
        _o[#_o+1]=((_b%16)*16+math.floor(_c/4))%256
      end
    else
      if not _c or not _d then error("E3") end
      _o[#_o+1]=(_a*4+math.floor(_b/16))%256
      _o[#_o+1]=((_b%16)*16+math.floor(_c/4))%256
      _o[#_o+1]=((_c%4)*64+_d)%256
    end
  end
  return _o
end
local function ${v.unkey}(_bytes,_key,_rot,_srcLen)
  local _o={}
  local _kb={}
  for _i=1,#_key,2 do
    _kb[#_kb+1]=tonumber(_key:sub(_i,_i+1),16)
  end
  local _max=math.min(#_bytes,_srcLen)
  for _i=1,_max do
    local _byte=(_bytes[_i]-_rot)%256
    _byte=(_byte ~ _kb[((_i-1)%#_kb)+1])&0xFF
    _o[_i]=string.char(_byte)
  end
  return table.concat(_o)
end
local ${v.encoded}=""
for _i=1,#${v.chunks} do ${v.encoded}=${v.encoded}..${v.chunks}[_i] end
local ${v.decoded}=${v.unkey}(${v.decode}(${v.encoded}),${v.key},_r,${v.srcLen})
local ${v.fn}=loadstring or load
local ${v.execute}=${v.fn}(${v.decoded},"FireLabPayload")
if ${v.execute} then ${v.execute}() else error("E4") end
`;
}

